import{_ as t,a as i}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as a,o as s,c as n,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Configuration et accès WebDAV","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/Safety/webdav-site-access.md","filePath":"fr-FR/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),r={name:"fr-FR/Safety/webdav-site-access.md"};function d(l,e,c,u,p,h){return s(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="configuration-et-acces-webdav" tabindex="-1">Configuration et accès WebDAV <a class="header-anchor" href="#configuration-et-acces-webdav" aria-label="Permalink to &quot;Configuration et accès WebDAV&quot;">​</a></h1><p>ImgBed peut exposer un accès WebDAV pour consulter les fichiers depuis l’explorateur du système ou un client compatible.</p><h2 id="quand-l-utiliser" tabindex="-1">Quand l’utiliser <a class="header-anchor" href="#quand-l-utiliser" aria-label="Permalink to &quot;Quand l’utiliser&quot;">​</a></h2><ul><li>Vous souhaitez consulter les fichiers depuis Windows ou macOS.</li><li>Vous utilisez un client WebDAV pour organiser des fichiers.</li><li>Vous devez accéder aux fichiers hors du panneau d’administration.</li></ul><h2 id="connexion-depuis-windows-11" tabindex="-1">Connexion depuis Windows 11 <a class="header-anchor" href="#connexion-depuis-windows-11" aria-label="Permalink to &quot;Connexion depuis Windows 11&quot;">​</a></h2><ol><li>Ouvrez l’Explorateur de fichiers.</li><li>Faites un clic droit sur <code>Ce PC</code>.</li><li>Choisissez <code>Ajouter un emplacement réseau</code>.</li><li>Saisissez l’URL WebDAV.</li><li>Entrez l’utilisateur et le mot de passe.</li><li>Vérifiez que le contenu s’ouvre comme un dossier.</li></ol><p><img src="'+t+'" alt="Configuration WebDAV sous Windows 11" loading="lazy"></p><p>Si la connexion est correcte, le contenu apparaît dans l’Explorateur.</p><p><img src="'+i+'" alt="WebDAV sous Windows" loading="lazy"></p><h2 id="identifiants" tabindex="-1">Identifiants <a class="header-anchor" href="#identifiants" aria-label="Permalink to &quot;Identifiants&quot;">​</a></h2><p>Utilisez les identifiants WebDAV configurés dans ImgBed. Pour plus de sécurité, préférez un compte aux droits limités plutôt qu’un compte principal partagé.</p><h2 id="en-cas-d-echec-de-connexion" tabindex="-1">En cas d’échec de connexion <a class="header-anchor" href="#en-cas-d-echec-de-connexion" aria-label="Permalink to &quot;En cas d’échec de connexion&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Point</th><th>À vérifier</th></tr></thead><tbody><tr><td>URL</td><td>Elle contient <code>https://</code> et correspond à la bonne adresse WebDAV</td></tr><tr><td>Identifiants</td><td>Utilisateur et mot de passe corrects</td></tr><tr><td>Permissions</td><td>Lecture et écriture autorisées dans le dossier cible</td></tr><tr><td>Client</td><td>Windows ou le client WebDAV ne bloque pas la connexion</td></tr></tbody></table><p>Si seule la consultation de capacité échoue alors que les uploads fonctionnent, le serveur WebDAV peut simplement ne pas fournir d’information de quota.</p>',14)])])}const _=a(r,[["render",d]]);export{b as __pageData,_ as default};
